import arrow from "./arrow.svg";
import { Banner, Box, Boxes, BoxWrapper } from "./banner.style";
import { LandingPage, Heading, Subheading, Arrow } from "./landing.style";
import { ScrollLanding, 
  // ScrollUp
 } from "./scroll.style";
import { 
  // Corridor, 
  Page } from "./webpage.style";

function App() {
  const [landing, setLanding] = useState(true);
  const [page, setPage] = useState(false);
  return (
    <>
      {landing && (
        <ScrollLanding
          id="landing"
          href="#page"
          onClick={() => {
            setPage(true);
            setTimeout(() => {
              setLanding(false);
            }, 750);
          }}
        >
          <LandingPage className="landing-page">
            <Heading> e g a &nbsp; c h e u n g 
            <Subheading> p l e a s e &nbsp; c l i c k &nbsp; a n y w h e r e </Subheading>
            </Heading>
            <Arrow tabIndex={-1} src={arrow} alt="arrow" />
          </LandingPage>
        </ScrollLanding>
      )}

      {page && <Page id="page">

        {/* <ScrollUp href="#landing"> */}

        <Banner src="/img/WomansRightQuiltjpg.jpg"/>
        {/* <Corridor src="/img/corridor.jpg"/> */}
        {/* </ScrollUp> */}
        <Boxes> <BoxWrapper><Box>a</Box></BoxWrapper>
        <Box>b</Box>
        <Box>c</Box>
        <Box>d</Box> </Boxes>
      </Page>}
    </>
  );
}

export default App;
